int lengthOfLastWord(char* s) {
    int n = (int)strlen(s), i = n - 1;
    while (i >= 0 && s[i] == ' ') i--;
    int end = i;
    while (i >= 0 && s[i] != ' ') i--;
    return end - i;
}
